import React from "react";

const tahoIconDataUri =
  "data:image/png;base64,";

const Icon = ({ className, ...props }: React.SVGProps<SVGSVGElement>) => (
  <svg
    width="512"
    height="512"
    viewBox="0 0 512 512"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    {...props}
    className={className}
  >
    <image href={tahoIconDataUri} width="512" height="512" />
  </svg>
);

export default Icon;
